// Data-URI copies of the app's public/images/branches/*.webp for the BranchCard preview.
// BranchCard hardcodes <img src="/images/branches/<branch>.webp"> (app-served assets);
// outside the app those 404. The preview swaps the srcs to these after mount so the card
// shows the component exactly as the app serves it. Regenerate if the webps change.
export const BRANCH_ICON_DATA: Record<string, string> = {
  '/images/branches/executive.webp': 'data:image/webp;base64,',
  '/images/branches/legislative.webp': 'data:image/webp;base64,',
  '/images/branches/judicial.webp': 'data:image/webp;base64,',
};
